def round_half_to_even(n):

    # Get decimal part
    decimal = n - int(n)

    # If decimal part is exactly 0.5
    if decimal == 0.5:
        # Round to nearest even number
        if int(n) % 2 == 0:
            return int(n)
        else:
            return int(n) + 1
    # Otherwise use regular rounding
    else:
        return round(n)

