                element_positions[element] = []
            element_positions[element].append(pos)

    # 创建结果列表
    result = []
    # 记录已处理的元素
    used = set()

    # 持续处理直到所有元素都被使用
    while len(used) < len(element_positions):
        # 找到当前可以添加的元素
