    result = {}

    # 遍历d1中的所有键值对
    for key, value in d1.items():
        # 如果键不在d2中，直接添加到结果中
        if key not in d2:
            result[key] = value
        # 如果键在d2中且level不为0
        elif level != 0:
            # 如果两个值都是字典，则递归比较
            if isinstance(value, dict) and isinstance(d2[key], dict):
