def format(
    self,
    sql: AnyStr,
    params: Union[Dict[Union[str, int], Any], Sequence[Any]],
) -> Tuple[AnyStr, Union[Dict[Union[str, int], Any], Sequence[Any]]]:

    # 检查参数类型是否匹配样式
    if self.in_style.is_named():
        if not isinstance(params, Mapping):
            raise TypeError("Named parameter style requires mapping params")
    else:
        if not isinstance(params, Sequence) or isinstance(params, (str, bytes)):
            raise TypeError("Positional parameter style requires sequence params")

    # 转换参数
    converted_params = {}
    if isinstance(params, Mapping):
        # 命名参数样式
        for key, value in params.items():
            converted_params[key] = self._converter.convert(value)
    else:
        # 序号参数样式
        converted_params = [self._converter.convert(value) for value in params]

    # 根据输出样式格式化SQL
    if self.out_style.is_named():
        # 如果输入是序号样式但输出需要命名样式
        if isinstance(converted_params, list):
            named_params = {f"p{i}": val for i, val in enumerate(converted_params)}
            formatted_sql = self._convert_positional_to_named(sql, len(converted_params))
            converted_params = named_params
        else:
            formatted_sql = sql
    else:
        # 如果输入是命名样式但输出需要序号样式
        if isinstance(converted_params, dict):
            param_list = []
            formatted_sql = self._convert_named_to_positional(sql, converted_params, param_list)
            converted_params = param_list
        else:
            formatted_sql = sql

    return formatted_sql, converted_params

def formatmany(
        self,
        sql: AnyStr,
        many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    # Convert each params in many_params using the converter
    converted_params = [self._converter.convert_many(params) for params in many_params]

    # If no params provided, return original sql and empty list
    if not converted_params:
        return sql, []

    # Get the first converted params to determine type
    first_params = converted_params[0]

    # For named parameters (dict)
    if isinstance(first_params, dict):
        # Verify all params are dicts
        if not all(isinstance(p, dict) for p in converted_params):
            raise TypeError("All parameters must be of the same type")
        return sql, converted_params

    # For positional parameters (sequence)
    elif isinstance(first_params, (list, tuple)):
        # Verify all params are sequences
        if not all(isinstance(p, (list, tuple)) for p in converted_params):
            raise TypeError("All parameters must be of the same type")
        return sql, converted_params

    else:
        raise TypeError("Parameters must be either dict or sequence type")

