def _group_files_by_xml_filename(source, xmls, files):

    result = {}

    # 遍历所有XML文件
    for xml in xmls:
        # 获取XML文件名(不含扩展名)
        xml_name = xml.rsplit('.', 1)[0]

        # 找到与该XML文件名相关的所有文件
        related_files = []
        for file in files:
            # 如果文件名以XML文件名开头
            if file.startswith(xml_name):
                related_files.append(file)

        # 如果找到相关文件，则添加到结果字典中
        if related_files:
            result[xml_name] = {
                'source': source,
                'xml': xml,
                'files': related_files
            }

    return result

