def size_to_bytes(size: str) -> int:

    units = {
        'K': 1000,
        'M': 1000000,
        'G': 1000000000,
        'T': 1000000000000,
        'P': 1000000000000000,
        'E': 1000000000000000000,
        'KB': 1024,
        'MB': 1048576,
        'GB': 1073741824,
        'TB': 1099511627776,
        'PB': 1125899906842624,
        'EB': 1152921504606846976
    }

    size = size.strip().upper()

    # 如果只有数字,直接返回整数值
    if size.isdigit():
        return int(size)

    # 提取数字和单位
    number = ''
    unit = ''
    for char in size:
        if char.isdigit() or char == '.':
            number += char
        else:
            unit += char

    # 如果没有找到有效单位,返回原始数字
    if not unit or unit not in units:
        return int(float(number))

    # 计算字节数
    return int(float(number) * units[unit])

