def _dictsum(dicts):

    if not dicts:
        return {}

    # 获取所有字典中的所有唯一键
    all_keys = set().union(*dicts)

    # 创建结果字典
    result = {}

    # 对每个键进行遍历
    for key in all_keys:
        # 将所有字典中该键对应的值相加
        result[key] = sum(d.get(key, 0) for d in dicts)

    return result

