def is_gitbash():

    import os
    import sys

    # 检查是否在Windows系统
    if os.name != 'nt':
        return False

    # 检查环境变量中是否包含MINGW或MSYS
    env_keys = os.environ.keys()
    for key in ['MINGW_PREFIX', 'MSYSTEM']:
        if key in env_keys:
            return True

    # 检查终端程序名称
    if sys.stdout.isatty():
        term = os.environ.get('TERM')
        if term and ('mingw' in term.lower() or 'msys' in term.lower()):
            return True

    return False

