def from_raw_values(cls, values):

    bookmarks = []
    for value in values:
        # 移除空白字符
        value = value.strip()

        # 跳过空行
        if not value:
            continue

        try:
            # 尝试解析书签字符串
            bookmark = cls._parse_raw_value(value)
            bookmarks.append(bookmark)
        except ValueError:
            # 如果解析失败则跳过该行
            continue

    # 返回新的 Bookmarks 对象
    return cls(bookmarks)

