def xml_children_as_dict(node):

    result = {}
    for child in node:
        # 跳过注释等非元素节点
        if not hasattr(child, 'tag'):
            continue
        # 使用标签名作为键,节点对象作为值
        result[child.tag] = child
    return result

def xml_children_as_dict(node):

    result = {}
    for child in node:
        # 跳过注释等非元素节点
        if not hasattr(child, 'tag'):
