def _convert_non_cli_args(self, parser_name, values_dict):

    if not values_dict:
        return

    # 获取该解析器的参数定义
    parser = self._parsers.get(parser_name)
    if not parser:
        return

    # 遍历所有参数
    for arg_name, value in values_dict.items():
        # 跳过None值
        if value is None:
            continue

        # 获取参数的类型
        arg_type = None
        for action in parser._actions:
            if action.dest == arg_name:
                arg_type = action.type
                break

        # 如果找到类型定义且不是str,进行类型转换
        if arg_type and arg_type != str:
            try:
                # 处理列表类型
                if isinstance(value, list):
                    values_dict[arg_name] = [arg_type(v) for v in value]
                else:
                    values_dict[arg_name] = arg_type(value)
            except (ValueError, TypeError):
                # 转换失败时保持原值
                continue

def get_plugin_spec_flatten_dict(plugin_dir):

    import os
    import yaml

    # 初始化结果字典
    result = {}

    # 读取插件目录下的 plugin.yaml 文件
    spec_file = os.path.join(plugin_dir, 'plugin.yaml')
    if not os.path.exists(spec_file):
        return result

    # 读取 YAML 文件
    with open(spec_file, 'r', encoding='utf-8') as f:
        try:
            spec = yaml.safe_load(f)
        except yaml.YAMLError:
            return result

    def flatten_dict(d, parent_key='', sep='.'):

        items = []
        for k, v in d.items():
            new_key = f"{parent_key}{sep}{k}" if parent_key else k

            if isinstance(v, dict):
                items.extend(flatten_dict(v, new_key, sep=sep).items())
            else:
                items.append((new_key, v))

        return dict(items)

    # 扁平化字典
    if isinstance(spec, dict):
        result = flatten_dict(spec)

    return result

